/**
 * Route colocated client scripts → `/assets/routes/...` URLs.
 * Generated by scripts/build-client-js.mjs — do not edit by hand.
 */

export const routeClientScripts = {
  "home": ["/assets/routes/home/page.client.js"] as const,
} as const;

export type RouteClientScriptBundleKey = keyof typeof routeClientScripts;

export function clientScriptsForRouteDir(dir: string): readonly string[] {
  const map = routeClientScripts as Record<string, readonly string[]>;
  return map[dir] ?? [];
}
